const getGapTime = function(t){
  let minutes = parseInt(t/1000/60)
  let second = parseInt((t/1000)%60)
  if(minutes<10){
    minutes='0'+minutes
  }
  if(second<10){
    second = '0'+second
  }
  let diffTime = `${minutes}:${second}`
  return diffTime;
}
const getCount = function(c){
   if(c>=10000){
     c = Math.round(c/10000)+'万'
   }
   return c
}
import moment from "moment"
const filterDate = function(v){
  return moment(v).format('YYYY年MM月DD日 hh:mm:ss')
}
const filterDate2 = function(v){
  return moment(v).format('YYYY年MM月DD日 hh:mm:ss').substring(0,11)
}
export default {
  getGapTime,
  getCount,
  filterDate,
  filterDate2
}